// Suppress verbose Baileys session logs
const _origStdoutWrite = process.stdout.write.bind(process.stdout)
process.stdout.write = (chunk, encoding, callback) => {
    const str = typeof chunk === 'string' ? chunk : chunk.toString()
    // Filter log verbose Baileys yang tidak penting
    if (str.includes('Closing open session') || 
        str.includes('Closing session:') ||
        str.includes('SessionEntry') ||
        str.includes('chainKey:') ||
        str.includes('ephemeralKeyPair') ||
        str.includes('lastRemoteEphemeralKey') ||
        str.includes('currentRatchet') ||
        str.includes('pendingPreKey') ||
        str.includes('remoteIdentityKey') ||
        str.includes('registrationId') ||
        str.includes('indexInfo') ||
        str.includes('baseKeyType') ||
        str.includes('preKeyId') ||
        str.includes('<Buffer ') ||
        str.includes('BTXrJc')) {
        if (callback) callback()
        return true
    }
    return _origStdoutWrite(chunk, encoding, callback)
}

// в•җв•җ Limit check functions в•җв•җ
function checkLimit(pool, senderNumber, maxCount, windowMs) {
    const now = Date.now()
    if (!pool[senderNumber]) pool[senderNumber] = []
    pool[senderNumber] = pool[senderNumber].filter(t => now - t < windowMs)
    if (pool[senderNumber].length >= maxCount) {
        const tunggu = Math.ceil((windowMs - (now - pool[senderNumber][0])) / 60000)
        return { ok: false, tunggu }
    }
    pool[senderNumber].push(now)
    return { ok: true }
}

function getMaxChars(fontSize) {
    return Math.floor(462 / (parseInt(fontSize) * 0.55))
}

function wrapLines(text, maxChars) {
    const words = text.split(' ')
    const lines = []
    let currentLine = ''
    words.forEach(word => {
        while (word.length > maxChars) {
            if (currentLine) { lines.push(currentLine); currentLine = '' }
            lines.push(word.slice(0, maxChars))
            word = word.slice(maxChars)
        }
        if (!word) return
        const candidate = currentLine ? currentLine + ' ' + word : word
        if (candidate.length <= maxChars) { currentLine = candidate }
        else { if (currentLine) lines.push(currentLine); currentLine = word }
    })
    if (currentLine) lines.push(currentLine)
    return lines
}

function buildDrawtextFilter(lines, fontSize, startY, fontColor, borderColor, isBold = false) {
    const lineHeight = parseInt(fontSize) + 10
    const totalHeight = lines.length * lineHeight
    const baseY = startY === 'center' ? `(h-${totalHeight})/2` : startY === 'top' ? '20' : `h-${totalHeight + 20}`
    return lines.map((line, i) => {
        const escaped = line.replace(/\\/g,'\\\\').replace(/'/g,"\\'").replace(/:/g,'\\:').replace(/\[/g,'\\[').replace(/\]/g,'\\]')
        const yExpr = i === 0 ? baseY : `${baseY}+${i * lineHeight}`
        let filter = `drawtext=text='${escaped}':fontcolor=${fontColor}:fontsize=${fontSize}:x=(w-text_w)/2:y=${yExpr}`
        if (isBold) filter += `:borderw=4:bordercolor=${fontColor}`
        else if (borderColor) filter += `:borderw=3:bordercolor=${borderColor}`
        return filter
    }).join(',')
}

