                    await sendWithTyping(from, { text: 'вӯҗ *ZODIAK ' + namaZodiak.toUpperCase() + '*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n' + result }, { quoted: msg })
