                    let suhu = 'N/A'
                    try { const { execSync } = require('child_process'); const tempRaw = execSync('cat /sys/class/thermal/thermal_zone0/temp 2>/dev/null || echo 0', { encoding: 'utf8' }).trim(); if (parseInt(tempRaw) > 0) suhu = (parseInt(tempRaw) / 1000).toFixed(1) + 'В°C' } catch(e) {}
                    let health = 'рҹҹў Bot sehat walafiat!'
                    if (parseFloat(cpuLoad) > 80 || ramPct > 90) health = 'рҹ”ҙ Overload! Perlu restart.'
