                    let t = `рҹ–ҘпёҸ *STATUS SERVER BOT*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ’» *Platform:* ${os.platform()} ${os.arch()}\nвҸұпёҸ *Uptime:* ${days} hari ${hours} jam ${mins} menit\nрҹ“Ҡ *CPU Load:* ${cpuLoad}% (${cpuCount} core)\nрҹҢЎпёҸ *Suhu CPU:* ${suhu}\nрҹ“Ҳ *RAM Used:* ${(usedRam/1024/1024/1024).toFixed(2)} GB / ${(totalRam/1024/1024/1024).toFixed(2)} GB (${ramPct}%)\nрҹ’ҫ *Disk:* ${diskInfo}\nрҹӨ– *Bot RAM:* ${(mem.rss/1024/1024).toFixed(1)} MB\n\n_${health}_`
