                for (let i = 4; i < lenGP; i++) pw += charset[Math.floor(Math.random() * charset.length)]
                pw = pw.split('').sort(() => Math.random() - 0.5).join('')
                let t = `рҹ”җ *PASSWORD GENERATOR*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ”‘ *Password (${lenGP} karakter):*\n\`${pw}\`\n\nрҹ’Ә *Kekuatan:* SANGAT KUAT вң…\nвң… Termasuk: Huruf besar, kecil, angka, simbol\n\nвҡ пёҸ *Catatan:* Jangan simpan password di chat!`
