            if (lowerText === '.totalfitur') {
                await reactWait(from, msg.key)
                const allCanUse = ['.menu','/info','/tools','/stikermenu','/dl','/game','/cek','/user','.ping','.ai','.surf','.cuaca','.track','.gempa','.udara','.jadwalsholat','.kiblat','.lacak','.ongkir','.harga','.kurs','.fakta','.translate','.cekip','.ip','.topgame','.cp','.play','.hd','.blur','.unblur','.bw','.flip','.small','.stabil','.stabilpro','.toaudio','.combo1','.combo2','.combo3','.crop','.rotate','.enhance','.colorize','.animate','.cartoon','.remaster','.meme','.reverse','.speed','.extractframe','.compress','.gif','.audioeffect','.sticker','.stickervid','.brat','.bratvid','.dsticker','.quote','.pin','.qr','.teks','.download','.downloadnw','.downloadsound','.ds','.d','.tt','.yt','.fb','.ins','.x','.tts','.makanan','.kalori','.tanaman','.hama','.objek','.baca','.artikan','.cekmata','.cekkulit','.wajahku','.umurku','.emosiku','.mirip','.hitunghadir','.cektanda','.cektulis','.cekrek','.ceknomor','.cekemail','.cekpw','.buatpw','.trivia','.scramble','.tebakangka','.compliment','.roast','.confession','.motivasi','.profile','.afk','.back','.birthday','.remind','.note','.poll','.vote','.pollresult','.usnme','.lastseen','.info','.tools','.stikermenu','.dl','.game','.cek','.user','.deteksi','.status','.server','.waifu','.anime','.genpw','.harini','.haribesar','.tebakgambar','.jawab','.ttext','.join','.sb','.berita','.saham','.kripto','.trending','.wiki','.lirik','.resep','.film','.curhatan','.zodiak','.csh','.artis','.sig','.totalfitur','.joinserver','.scanqr','.sisigelap','.gemoji','.haudio','.template1','.template2','.template3']
                const premiumOnly = ['.enhance2x','.enhance4x','.enhance8x','.beautify','.cinematic','.nightmode','.glitch','.vignette','.combopro','.oldphoto','.slowmo','.neonlight','.watermark','.duotone']
                const ownerOnly = ['/boton','/botoff','/onbot','/offbot','/welcome','/owner','/unowner','/add','/upd','/del','/ban','/unban','/listban','/kick','/tagall','/spam','/backup','/addtodata','/delall','/delallshop','/antilink','/antiword','/banword','/unbanword','/banwordlist','/dpp','/dpg','/dstatuss','/dstatus','/rvo','/premium','/unpremium','/listpremium','/listm','/inputusnon','/inputusnoff','/usn','/usnowner','/sstabilpro','/globalchat','.katahari','.namaarti','.hitung','.konversi','.cuacaminggu','.tanyaislam','.jeniskucing','.tebakkata','.hobimu','.singkat','.perbaiki','.buatpuisi','.buatcerita','.lawak','.terjemahsuara','.iqtest','.carivisit','.motivasibahasa','.cakmimin','.tipssehat','.debat','.sinyalwifi','.tagmention','.kamus','.sinonim','.antonim','.jenishp','.bmi','.zodiak2','.kalimatacak','.timeleft','.qotd','.palindrome','.suhukonversi','.hitungumur','.acak','.matauang','.faktagila','.namapanggilan','.hdvideo4k','.bgremove','.colorgrade','.denoise','.stabilpremium','.upscalevid','.aiportrait','.autocaption','.removeobj','.faceswap','/siaran','/resetlimit','/ceklimit','/mute','/unmute','/cleartemp','/botinfo','/pinpesan','/setprefix','.negara','.ibu','.matanegara','.bahasanegara','.penduduk','.luasnegara','.flagfoto','.pemimpin','.sejarahnegara','.batasnegara','.kotabesar','.negarabenua','.hdinegara','.agamanegara','.hymne','.iqc','.tebakbendera','.tebakhewan','.tebakfilm','.matematika','.tebakibu','.tebaksport','.siapakuini','.tebaklagu','.tebaktahun','.tebakmerek','.tebakwarna','.tebakprovince','.tebakrumus','.emojitebak','.faktaatauhoaks','.silogisme','.tebaksuara','.tebakprofesi','.tebakangkaajaib','.level','.leaderboard','.lb','.menu','.menu1','.menu2','.menu3','.menu4','.menu5','.menu6','.menu7','.menu8','.menu9','.menu10','.menuprem','.menuowner','.tebakperibahasa','.tebakng','.tebakartis','.tebaklirik','.tebakmasakan','.tebakmovie','.tebakgames','.tebakibu2','.tebakbahasa','.tebakolahraga2','.tebakunsur','.tebakkata2','.tebakangka2','.tebakhuruf','.tebaksejarah','.tebakbrand','.tebakhewan2','.tebaknomor','.tebakistilah','.tebakwarna2','.lockgrup','.unlockgrup','.listgrup','.promoteadmin','.demoteadmin','.sketch','.mirror','.pixelate','.warpspeed','.boomerang','.colorize2','.tiltshift']
                let txt = `рҹ“Ҡ *TOTAL FITUR ROMA BOT*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n`
                txt += `рҹ‘Ҙ *Fitur ALL (bisa dipakai semua):*\n`
                allCanUse.forEach((f, i) => txt += `${i+1}. ${f}\n`)
                txt += `\nрҹ“Ҡ *Total All Can Use:* ${allCanUse.length} fitur\n\n`
                txt += `рҹ’Һ *Fitur PREMIUM only (3x/24jam):*\n`
                premiumOnly.forEach((f, i) => txt += `${i+1}. ${f}\n`)
                txt += `\nрҹ“Ҡ *Total Premium:* ${premiumOnly.length} fitur\n\n`
                txt += `рҹ‘‘ *Fitur OWNER only:*\n`
                ownerOnly.forEach((f, i) => txt += `${i+1}. ${f}\n`)
                txt += `\nрҹ“Ҡ *Total Owner:* ${ownerOnly.length} fitur\n`
                txt += `\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                txt += `рҹ”ў *GRAND TOTAL: ${allCanUse.length + premiumOnly.length + ownerOnly.length} fitur*\n`
                txt += `в—Ұ All: ${allCanUse.length}\nв—Ұ Premium: ${premiumOnly.length}\nв—Ұ Owner: ${ownerOnly.length}`
                await sendWithTyping(from, { text: txt }, { quoted: msg })
                await reactDone(from, msg.key); return
            }

            // в•җв•җ /joinserver (namagame) вҖ” Cari server Roblox в•җв•җ
            if (lowerText.startsWith('.joinserver ')) {
                const gameName = fullText.slice(12).trim()
                if (!gameName) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .joinserver [nama game roblox]\nContoh: .joinserver Murder Mystery 2' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    // Cari game via Roblox search API
                    const searchResp = await axios.get(`https://apis.roblox.com/search-api/omni-search?searchQuery=${encodeURIComponent(gameName)}&sessionId=&pageToken=&pageType=all`, { timeout: 10000, headers: { 'User-Agent': 'Mozilla/5.0' } })
                    let universeId = null, gameTitle = '', gamePlaying = 0, gameUrl = ''
                    // Fallback: try catalog/games search
                    try {
                        const resp2 = await axios.get(`https://games.roblox.com/v1/games/list?model.keyword=${encodeURIComponent(gameName)}&model.maxRows=5`, { timeout: 10000, headers: { 'User-Agent': 'Mozilla/5.0' } })
                        if (resp2.data?.games?.length > 0) {
                            const topGame = resp2.data.games.sort((a, b) => b.playerCount - a.playerCount)[0]
                            universeId = topGame.universeId
                            gamePlaying = topGame.playerCount
                            gameUrl = `https://www.roblox.com/games/${topGame.placeId}`
                            gameTitle = topGame.name || gameName
                        }
                    } catch(e2) {}
                    if (!universeId) {
                        // Fallback: cari via keyword manual
                        const aiResult = await askAI(`Berikan informasi singkat tentang game Roblox bernama "${gameName}". Sebutkan: nama resmi game, jumlah pemain aktif kira-kira, genre, dan link roblox.com kalau tahu. Jawab singkat dalam bahasa Indonesia.`, 'joinserver')
                        return await sendWithTyping(from, { text: `рҹҺ® *INFO GAME: ${gameName}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n${aiResult}\n\nрҹ”— Cari manual: https://www.roblox.com/search/people?keyword=${encodeURIComponent(gameName)}\n\n_вҡ пёҸ Untuk join server, buka Roblox langsung & cari game ini._` }, { quoted: msg })
                    }
                    // Ambil detail game
                    let txt = `рҹҺ® *ROBLOX SERVER FINDER*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                    txt += `рҹҸ·пёҸ *Game:* ${gameTitle}\n`
                    txt += `рҹ‘Ҙ *Pemain aktif:* ${gamePlaying.toLocaleString()}\n`
                    txt += `рҹ”— *Link:* ${gameUrl}\n\n`
                    txt += `рҹ’Ў *Cara join server terbaik:*\n`
                    txt += `в—Ұ Klik link di atas вҶ’ klik Play\n`
                    txt += `в—Ұ Atau cari di Roblox: *${gameTitle}*\n\n`
                    txt += `_вң… Server direkomendasikan berdasarkan pemain aktif terbanyak_`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) {
                    await sendWithTyping(from, { text: `вқҢ Gagal mencari server game "${gameName}". Coba cek langsung di Roblox.com` }, { quoted: msg })
                    await reactDone(from, msg.key)
                }
                return
            }

            // в•җв•җ /scanqr вҖ” Scan QR Code dari foto в•җв•җ
            if (lowerText === '.scanqr') {
                const qmScan = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                const isImgScan = msg.message.imageMessage || (qmScan && qmScan.imageMessage)
                if (!isImgScan) return await sendWithTyping(from, { text: 'вҡ пёҸ Reply foto QR Code dulu lalu ketik /scanqr\nContoh: (reply foto QR) вҶ’ /scanqr' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const bd = await downloadMedia(isImgScan, 'image')
                    const imgPath = `./qrscan_${Date.now()}.jpg`
                    fs.writeFileSync(imgPath, bd)
                    // Encode ke base64 dan kirim ke zxing API
                    const base64Img = bd.toString('base64')
                    let qrResult = null
                    try {
                        const resp = await axios.post('https://api.qrserver.com/v1/read-qr-code/', { base64: base64Img }, { timeout: 15000 })
                        if (resp.data?.[0]?.symbol?.[0]?.data) qrResult = resp.data[0].symbol[0].data
                    } catch(e2) {}
                    if (!qrResult) {
                        // Fallback: zxing
                        try {
                            const formData = new (require('form-data'))()
                            formData.append('f', fs.readFileSync(imgPath), { filename: 'qr.jpg', contentType: 'image/jpeg' })
                            const resp2 = await axios.post('https://zxing.org/w/decode', formData, { headers: formData.getHeaders(), timeout: 15000 })
                            const match = resp2.data.match(/Parsed Result<\/em><\/td>\s*<td>([\s\S]*?)<\/td>/i)
                            if (match) qrResult = match[1].replace(/<[^>]+>/g, '').trim()
                        } catch(e3) {}
                    }
                    try { fs.unlinkSync(imgPath) } catch(e) {}
                    if (!qrResult) return await sendWithTyping(from, { text: 'вқҢ Gagal membaca QR Code. Pastikan foto jelas dan QR tidak blur.' }, { quoted: msg })
                    let txt = `рҹ“ұ *HASIL SCAN QR CODE*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                    txt += `рҹ“Ӣ *Isi QR:*\n${qrResult}\n\n`
                    if (qrResult.startsWith('http')) txt += `рҹ”— *Ini adalah link/URL*\nвҡ пёҸ Hati-hati klik link tidak dikenal!`
                    else if (qrResult.startsWith('WIFI:')) txt += `рҹ“¶ *Ini adalah data WiFi*`
                    else if (qrResult.startsWith('tel:')) txt += `рҹ“һ *Ini adalah nomor telepon*`
                    else if (qrResult.startsWith('mailto:')) txt += `рҹ“§ *Ini adalah email*`
                    else txt += `рҹ“қ *Ini adalah teks biasa*`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal scan QR.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /haudio вҖ” Naikkan/turunkan volume audio в•җв•җ
            if (lowerText.startsWith('.haudio ')) {
                const volStr = fullText.split(' ')[1]
                const vol = parseInt(volStr)
                if (isNaN(vol) || vol < -100 || vol > 100) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .haudio [volume -100 sampai 100]\nContoh: (reply audio/video) вҶ’ /haudio 50\nContoh: (reply audio/video) вҶ’ /haudio -30' }, { quoted: msg })
                const qmHA = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                const isAudHA = msg.message.audioMessage || (qmHA && qmHA.audioMessage)
                const isVidHA = msg.message.videoMessage || (qmHA && qmHA.videoMessage)
                if (!isAudHA && !isVidHA) return await sendWithTyping(from, { text: 'вҡ пёҸ Reply audio/video dulu lalu ketik /haudio [volume]\nRange: -100 (kecil) sampai 100 (keras)\nContoh: (reply audio) вҶ’ /haudio 50' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    let bdHA, typeHA = 'audio'
                    if (isAudHA) bdHA = await downloadMedia(isAudHA, 'audio')
                    else { bdHA = await downloadMedia(isVidHA, 'video'); typeHA = 'video' }
                    const extIn = typeHA === 'audio' ? 'mp3' : 'mp4'
                    const ipHA = `./ha_in_${Date.now()}.${extIn}`; const opHA = `./ha_out_${Date.now()}.mp3`
                    fs.writeFileSync(ipHA, bdHA)
                    // Convert vol dari -100..100 ke ffmpeg dB: vol=0 = 0dB, vol=100 = +20dB, vol=-100 = -20dB
                    const dbVal = (vol / 100) * 20
                    const dbStr = dbVal >= 0 ? `+${dbVal.toFixed(1)}dB` : `${dbVal.toFixed(1)}dB`
                    const volumeFilter = vol >= 0 ? `volume=${1 + vol/100 * 4}` : `volume=${Math.max(0.01, 1 + vol/100)}`
                    const inputFlag = typeHA === 'video' ? '-vn' : ''
                    await execPromise(`ffmpeg -i ${ipHA} ${inputFlag} -af "${volumeFilter}" -acodec libmp3lame -ab 128k ${opHA}`)
                    const audioOut = fs.readFileSync(opHA)
                    await sendWithTyping(from, { audio: audioOut, mimetype: 'audio/mpeg', ptt: false }, { quoted: msg })
                    await sendWithTyping(from, { text: `рҹ”Ҡ *VOLUME ADJUSTED!*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ“Ҡ Perubahan: ${vol > 0 ? '+' : ''}${vol}% (${dbStr})\n${vol > 0 ? 'рҹ”Ҡ Volume dikeraskan' : vol < 0 ? 'рҹ”Ҳ Volume dikecilkan' : 'рҹ”ү Tidak ada perubahan'}` }, { quoted: msg })
                    await reactDone(from, msg.key)
                    try { fs.unlinkSync(ipHA); fs.unlinkSync(opHA) } catch(e) {}
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal mengatur volume audio.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /sisigelap вҖ” Info sisi gelap suatu negara в•җв•җ
            if (lowerText.startsWith('.sisigelap ')) {
                const negara = fullText.slice(11).trim()
                if (!negara) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .sisigelap [negara]\nContoh: .sisigelap Amerika' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const result = await askAI(`Jelaskan secara super duper detail "sisi gelap" dari negara ${negara}. Bahas: korupsi, kejahatan terorganisir, ketimpangan sosial, pelanggaran HAM, kebijakan kontroversial, sejarah kelam, masalah lingkungan, dan fakta-fakta mencengangkan yang jarang diketahui publik. Beri referensi data & fakta nyata. Format rapi dengan emoji. Jawab dalam bahasa Indonesia secara mendalam dan jujur.`, senderNumber)
                    await sendWithTyping(from, { text: `рҹҢ‘ *SISI GELAP: ${negara.toUpperCase()}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n${result}\n\n_вҡ пёҸ Informasi bersumber dari data publik & AI. Untuk riset lanjutan, cek sumber terpercaya._` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal mengambil informasi.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /gemoji вҖ” Gabungkan 2 emoji jadi gambar baru в•җв•җ
            if (lowerText.startsWith('.gemoji ')) {
                const emojiInput = fullText.slice(8).trim()
                // Parse: emoji1+emoji2
                const parts = emojiInput.split('+').map(e => e.trim()).filter(Boolean)
                if (parts.length < 2) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .gemoji [emoji1]+[emoji2]\nContoh: .gemoji рҹҳҖ+рҹ”Ҙ\nContoh: .gemoji вқӨпёҸ+рҹҳӯ' }, { quoted: msg })
                const emoji1 = parts[0], emoji2 = parts[1]
                await reactWait(from, msg.key)
                try {
                    // Google Emoji Kitchen API
                    const toCodepoint = (emoji) => {
                        const codePoints = []
                        for (const char of emoji) {
                            const cp = char.codePointAt(0)
                            if (cp && cp > 0x1F) codePoints.push(cp.toString(16))
                        }
                        return codePoints.filter(c => c !== 'fe0f' && c !== '200d').join('-')
                    }
                    const cp1 = toCodepoint(emoji1)
                    const cp2 = toCodepoint(emoji2)
                    // Try both orders (Google Emoji Kitchen supports both)
                    const urls = [
                        `https://www.gstatic.com/android/keyboard/emojikitchen/20230301/u${cp1}/u${cp1}_u${cp2}.png`,
                        `https://www.gstatic.com/android/keyboard/emojikitchen/20230301/u${cp2}/u${cp2}_u${cp1}.png`,
                        `https://www.gstatic.com/android/keyboard/emojikitchen/20201001/u${cp1}/u${cp1}_u${cp2}.png`,
                        `https://www.gstatic.com/android/keyboard/emojikitchen/20201001/u${cp2}/u${cp2}_u${cp1}.png`,
                    ]
                    let imgBuf = null
                    for (const url of urls) {
                        try {
                            const resp = await axios.get(url, { responseType: 'arraybuffer', timeout: 8000 })
                            if (resp.status === 200 && resp.data.length > 100) { imgBuf = Buffer.from(resp.data); break }
                        } catch(e2) {}
                    }
                    if (!imgBuf) return await sendWithTyping(from, { text: `вқҢ Kombinasi emoji ${emoji1}+${emoji2} tidak tersedia di Emoji Kitchen.\nCoba kombinasi emoji lain!` }, { quoted: msg })
                    await sendWithTyping(from, { image: imgBuf, caption: `вңЁ *EMOJI KITCHEN*\n${emoji1} + ${emoji2} = рҹҺү\n\n_Powered by Google Emoji Kitchen_` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal generate emoji. Coba kombinasi lain.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /template1 вҖ” Template JJ edit 1 foto в•җв•җ
            if (lowerText === '.template1') {
                const qmT1 = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                const isImgT1 = msg.message.imageMessage || (qmT1 && qmT1.imageMessage)
                if (!isImgT1) return await sendWithTyping(from, { text: 'вҡ пёҸ Reply 1 foto dulu lalu ketik /template1\nTemplate JJ Edit untuk 1 foto dengan efek estetik!' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const bd = await downloadMedia(isImgT1, 'image')
                    const ip = `./t1_in_${Date.now()}.jpg`; const op = `./t1_out_${Date.now()}.jpg`
                    fs.writeFileSync(ip, bd)
                    // Template 1: Aesthetic warm tone + vignette + soft light leak
                    await execPromise(`ffmpeg -i ${ip} -vf "scale=1080:1080:force_original_aspect_ratio=increase,crop=1080:1080,curves=r='0/0 0.5/0.58 1/1':g='0/0 0.5/0.5 1/0.95':b='0/0 0.5/0.42 1/0.85',eq=contrast=1.05:saturation=1.2:brightness=0.02,vignette=PI/3" -q:v 2 ${op}`)
                    await sendWithTyping(from, { image: fs.readFileSync(op), caption: `вңЁ *TEMPLATE 1 - JJ EDIT*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹҢё Warm aesthetic tone\nрҹҢ‘ Soft vignette\nвңЁ Color enhancement\nрҹ“җ Crop 1080x1080\n\n_Siap upload ke sosmed!_ рҹ”Ҙ` }, { quoted: msg })
                    await reactDone(from, msg.key); try { fs.unlinkSync(ip); fs.unlinkSync(op) } catch(e) {}
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal buat template.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /template2 вҖ” Template JJ edit 2 foto в•җв•җ
            if (lowerText === '.template2') {
                await sendWithTyping(from, { text: `рҹ“ё *TEMPLATE 2 - JJ EDIT (2 FOTO)*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\nCara pakai:\n1пёҸвғЈ Kirim foto pertama\n2пёҸвғЈ Balas foto pertama itu dengan foto kedua + ketik /template2start\n\n_Bot akan gabungkan 2 foto menjadi 1 template kolase estetik!_ вңЁ` }, { quoted: msg })
                return
            }

            // в•җв•җ /template2start вҖ” Proses 2 foto jadi template в•җв•җ
            if (lowerText === '.template2start') {
                const qmT2 = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                const isImgT2a = msg.message.imageMessage
                const isImgT2b = qmT2 && qmT2.imageMessage
                if (!isImgT2a || !isImgT2b) return await sendWithTyping(from, { text: 'вҡ пёҸ Kirim foto baru + reply foto lama, lalu ketik /template2start\nContoh: (kirim foto baru вҶ’ reply foto lama) вҶ’ /template2start' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const bd1 = await downloadMedia(isImgT2a, 'image')
                    const bd2 = await downloadMedia(isImgT2b, 'image')
                    const ip1 = `./t2_a_${Date.now()}.jpg`; const ip2 = `./t2_b_${Date.now()}.jpg`; const op = `./t2_out_${Date.now()}.jpg`
                    fs.writeFileSync(ip1, bd1); fs.writeFileSync(ip2, bd2)
                    // Template 2: Side by side dengan aesthetic filter
                    await execPromise(`ffmpeg -i ${ip1} -i ${ip2} -filter_complex "[0:v]scale=540:1080:force_original_aspect_ratio=increase,crop=540:1080,curves=r='0/0 0.5/0.55 1/1':g='0/0 0.5/0.48 1/0.92':b='0/0 0.5/0.4 1/0.82'[l];[1:v]scale=540:1080:force_original_aspect_ratio=increase,crop=540:1080,curves=r='0/0 0.5/0.55 1/1':g='0/0 0.5/0.48 1/0.92':b='0/0 0.5/0.4 1/0.82'[r];[l][r]hstack=inputs=2" -q:v 2 ${op}`)
                    await sendWithTyping(from, { image: fs.readFileSync(op), caption: `вңЁ *TEMPLATE 2 - JJ EDIT*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ–јпёҸ 2 foto digabung side-by-side\nрҹҢё Aesthetic warm filter\nрҹ“җ Ukuran: 1080x1080\n\n_Siap upload ke sosmed!_ рҹ”Ҙ` }, { quoted: msg })
                    await reactDone(from, msg.key); try { fs.unlinkSync(ip1); fs.unlinkSync(ip2); fs.unlinkSync(op) } catch(e) {}
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal buat template 2 foto.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /template3 вҖ” Template JJ edit 3 foto (kirim instruksi) в•җв•җ
            if (lowerText === '.template3') {
                await sendWithTyping(from, { text: `рҹ“ё *TEMPLATE 3 - JJ EDIT (3 FOTO)*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\nCara pakai:\n1пёҸвғЈ Kirim foto pertama\n2пёҸвғЈ Balas foto pertama, kirim foto kedua + /template3a\n3пёҸвғЈ Bot simpan foto 1&2, lalu kirim foto ketiga + /template3b\n\nAtau cara cepat:\nв—Ұ Ketik /template3quick dan kirim 3 foto sekaligus sebagai album\n\n_Bot gabungkan 3 foto jadi layout estetik!_ вңЁ` }, { quoted: msg })
                return
            }

            // в•җв•җ /template3a вҖ” Simpan foto 1 untuk template 3 в•җв•җ
            if (lowerText === '.template3a') {
                const qmT3a = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                const isImgT3a = msg.message.imageMessage
                const isImgT3a2 = qmT3a && qmT3a.imageMessage
                if (!isImgT3a && !isImgT3a2) return await sendWithTyping(from, { text: 'вҡ пёҸ Kirim/reply foto dulu lalu ketik /template3a' }, { quoted: msg })
                if (!fs.existsSync('./template3_temp')) fs.mkdirSync('./template3_temp')
                const imgToSave = isImgT3a || isImgT3a2
                const bd = await downloadMedia(imgToSave, 'image')
                const savePath = `./template3_temp/${senderNumber}_1.jpg`
                fs.writeFileSync(savePath, bd)
                await sendWithTyping(from, { text: `вң… *Foto 1 disimpan!*\nSekarang kirim foto ke-2 + ketik /template3b` }, { quoted: msg })
                return
            }

            // в•җв•җ /template3b вҖ” Proses 3 foto jadi template в•җв•җ
            if (lowerText === '.template3b') {
                const qmT3b = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                const isImgT3b = msg.message.imageMessage
                const isImgT3b2 = qmT3b && qmT3b.imageMessage
                if (!isImgT3b && !isImgT3b2) return await sendWithTyping(from, { text: 'вҡ пёҸ Kirim/reply foto dulu lalu ketik /template3b' }, { quoted: msg })
                const img1Path = `./template3_temp/${senderNumber}_1.jpg`
                if (!fs.existsSync(img1Path)) return await sendWithTyping(from, { text: 'вҡ пёҸ Foto 1 tidak ditemukan! Mulai ulang dari /template3a' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const imgToUse = isImgT3b || isImgT3b2
                    const bd = await downloadMedia(imgToUse, 'image')
                    const ip2 = `./t3_b_${Date.now()}.jpg`; const op = `./t3_out_${Date.now()}.jpg`
                    fs.writeFileSync(ip2, bd)
                    // Template 3: 3 foto - 1 besar atas, 2 kecil bawah
                    const ip1 = img1Path
                    const ip3Temp = `./t3_c_${Date.now()}.jpg`
                    // Buat foto 3 = foto 2 (mirrored sebagai variasi)
                    await execPromise(`ffmpeg -i ${ip2} -vf "hflip" -q:v 2 ${ip3Temp}`)
                    await execPromise(`ffmpeg -i ${ip1} -i ${ip2} -i ${ip3Temp} -filter_complex "[0:v]scale=1080:600:force_original_aspect_ratio=increase,crop=1080:600,curves=r='0/0 0.5/0.55 1/1':g='0/0 0.5/0.48 1/0.92':b='0/0 0.5/0.4 1/0.82'[top];[1:v]scale=540:480:force_original_aspect_ratio=increase,crop=540:480,curves=r='0/0 0.5/0.55 1/1':g='0/0 0.5/0.48 1/0.92':b='0/0 0.5/0.4 1/0.82'[bl];[2:v]scale=540:480:force_original_aspect_ratio=increase,crop=540:480,curves=r='0/0 0.5/0.55 1/1':g='0/0 0.5/0.48 1/0.92':b='0/0 0.5/0.4 1/0.82'[br];[bl][br]hstack=inputs=2[bottom];[top][bottom]vstack=inputs=2" -q:v 2 ${op}`)
                    await sendWithTyping(from, { image: fs.readFileSync(op), caption: `вңЁ *TEMPLATE 3 - JJ EDIT*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ–јпёҸ Layout 3 foto estetik\nрҹҢё 1 foto besar + 2 foto bawah\nрҹ“җ Ukuran: 1080x1080\n\n_Siap upload ke sosmed!_ рҹ”Ҙ` }, { quoted: msg })
                    await reactDone(from, msg.key)
                    try { fs.unlinkSync(ip2); fs.unlinkSync(ip3Temp); fs.unlinkSync(op); fs.unlinkSync(img1Path) } catch(e) {}
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal buat template 3 foto.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // FITUR OWNER BARU: /globalchat
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

            // в•җв•җ /globalchat вҖ” Kirim pesan ke semua kontak/grup (OWNER ONLY) в•җв•җ
            if (lowerText.startsWith('.globalchat ') || lowerText === '.globalchat') {
                if (!isOwner) return await sendWithTyping(from, { text: 'вҡ пёҸ Fitur /globalchat hanya untuk Owner.' }, { quoted: msg })
                const gcMsg = fullText.slice(12).trim()
                if (!gcMsg) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .globalchat [pesan]\nContoh: .globalchat Halo semua! Bot sedang maintenance.' }, { quoted: msg })
                // Cek konfirmasi
                if (!tempAccess[senderNumber + '_gc_confirm']) {
                    tempAccess[senderNumber + '_gc_pending'] = gcMsg
                    tempAccess[senderNumber + '_gc_confirm'] = 1
                    return await sendWithTyping(from, { text: `вҡ пёҸ *KONFIRMASI GLOBAL CHAT (1/2)*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ“ў Pesan yang akan dikirim:\n\n"${gcMsg}"\n\n_Kirim lagi /globalchat [pesan] yang SAMA untuk konfirmasi ke-2_\nвҡ пёҸ Pesan akan dikirim ke SEMUA kontak & grup!` }, { quoted: msg })
                }
                // Konfirmasi ke-2
                if (tempAccess[senderNumber + '_gc_pending'] !== gcMsg) {
                    delete tempAccess[senderNumber + '_gc_confirm']
                    delete tempAccess[senderNumber + '_gc_pending']
                    return await sendWithTyping(from, { text: 'вқҢ Pesan berbeda dari konfirmasi sebelumnya. Reset. Mulai ulang /globalchat' }, { quoted: msg })
                }
                delete tempAccess[senderNumber + '_gc_confirm']
                delete tempAccess[senderNumber + '_gc_pending']
                await reactWait(from, msg.key)
                await sendWithTyping(from, { text: `рҹҡҖ *Memulai pengiriman Global Chat...*\nрҹ“ў Pesan: "${gcMsg}"` }, { quoted: msg })
                // Ambil semua chat
                let successCount = 0, failCount = 0
                try {
                    const chats = await sock.groupFetchAllParticipating()
                    const groupIds = Object.keys(chats)
                    for (const gid of groupIds) {
                        try {
                            await sock.sendMessage(gid, { text: `рҹ“ў *BROADCAST*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n${gcMsg}\n\n_Pesan dari Owner Roma Bot_` })
                            successCount++
                            await new Promise(res => setTimeout(res, 1000))
                        } catch(e2) { failCount++ }
                    }
                } catch(e) {}
                await sendWithTyping(from, { text: `вң… *Global Chat Selesai!*\nвң… Terkirim: ${successCount} grup\nвқҢ Gagal: ${failCount}` }, { quoted: msg })
                await reactDone(from, msg.key); return
            }



            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // 20 FITUR BARU ALL CAN USE вҖ” WEB SCRAPER
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

            // в•җв•җ /katahari вҖ” Kata motivasi hari ini dari API в•җв•җ
            if (lowerText === '.katahari') {
                await reactWait(from, msg.key)
                try {
                    let quote = '', author = ''
                    // Try Indonesian quotes API
                    try {
                        const r = await axios.get('https://api.quotable.io/random?tags=motivational,inspirational', { timeout: 8000 })
                        quote = r.data.content; author = r.data.author
                    } catch(e) {}
                    if (!quote) {
                        const r2 = await axios.get('https://zenquotes.io/api/random', { timeout: 8000 })
                        quote = r2.data[0].q; author = r2.data[0].a
                    }
                    // Translate to Indonesian
                    const transUrl = `https://translate.googleapis.com/translate_a/single?client=gtx&sl=en&tl=id&dt=t&q=${encodeURIComponent(quote)}`
                    let quoteID = quote
                    try {
                        const tr = await axios.get(transUrl, { timeout: 8000, headers: { 'User-Agent': 'Mozilla/5.0' } })
                        quoteID = tr.data[0].map(x => x[0]).filter(Boolean).join('')
                    } catch(e) {}
                    await sendWithTyping(from, { text: `рҹҢ… *KATA HARI INI*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\nвңЁ "${quoteID}"\n\nвҖ” _${author}_\n\n_Powered by Quotable API_` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal ambil quote. Coba lagi nanti.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /namaarti [nama] вҖ” Arti nama dari API в•җв•җ
            if (lowerText.startsWith('.namaarti ')) {
                const nama = fullText.slice(10).trim()
                if (!nama) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .namaarti [nama]\nContoh: .namaarti Budi' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const r = await axios.get(`https://api.nationalize.io/?name=${encodeURIComponent(nama)}`, { timeout: 8000 })
                    const countries = r.data.country?.slice(0, 3).map(c => `${c.country_id} (${(c.probability * 100).toFixed(1)}%)`).join(', ') || 'Tidak diketahui'
                    // Behind the name API scrape
                    const wikiR = await axios.get(`https://id.wikipedia.org/w/api.php?action=opensearch&search=${encodeURIComponent('Nama ' + nama)}&limit=1&format=json`, { timeout: 8000 })
                    let wikiDesc = ''
                    if (wikiR.data[2]?.[0]) wikiDesc = wikiR.data[2][0]
                    // BabyNames scrape
                    let meaningText = wikiDesc || `Nama ${nama} adalah nama yang indah dengan berbagai makna bergantung asal budayanya.`
                    let txt = `вңЁ *ARTI NAMA: ${nama.toUpperCase()}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                    txt += `рҹ“ӣ *Nama:* ${nama}\n`
                    txt += `рҹҢҚ *Populer di:* ${countries}\n`
                    txt += `рҹ“– *Info:* ${meaningText.slice(0, 300)}\n`
                    txt += `\n_Data dari Nationalize.io & Wikipedia_`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal cek nama.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /hitung [ekspresi] вҖ” Kalkulator pintar в•җв•җ
            if (lowerText.startsWith('.hitung ')) {
                const expr = fullText.slice(8).trim()
                if (!expr) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .hitung [ekspresi]\nContoh: .hitung 25 * 4 + 100 / 2\nContoh: .hitung (50+30)*2' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const safe = expr.replace(/[^0-9+\-*/().% ]/g, '').trim()
                    if (!safe) return await sendWithTyping(from, { text: 'вҡ пёҸ Hanya boleh angka & operator + - * / ( )' }, { quoted: msg })
                    const result = Function('"use strict"; return (' + safe + ')')()
                    if (typeof result !== 'number' || !isFinite(result)) throw new Error('Hasil tidak valid')
                    await sendWithTyping(from, { text: `рҹ§® *KALKULATOR*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ“қ *Soal:* ${expr}\nвң… *Hasil:* *${result.toLocaleString('id-ID')}*` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Ekspresi tidak valid! Cek kembali penulisannya.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /konversi [nilai] [dari] [ke] вҖ” Konversi satuan via API в•җв•җ
            if (lowerText.startsWith('.konversi ')) {
                const parts = fullText.slice(10).trim().split(' ')
                if (parts.length < 3) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .konversi [nilai] [dari] [ke]\nContoh: .konversi 100 USD IDR\nContoh: .konversi 10 km mil' }, { quoted: msg })
                const [nilaiStr, dari, ke] = [parts[0], parts[1].toUpperCase(), parts[2].toUpperCase()]
                const nilai = parseFloat(nilaiStr)
                if (isNaN(nilai)) return await sendWithTyping(from, { text: 'вҡ пёҸ Nilai harus berupa angka!' }, { quoted: msg })
                await reactWait(from, msg.key)
                await reactWait(from, msg.key)
                try {
                    // Currency conversion
                    const currencyCodes = ['USD','IDR','EUR','GBP','JPY','SGD','MYR','AUD','CAD','CNY','KRW','THB']
                    if (currencyCodes.includes(dari) && currencyCodes.includes(ke)) {
                        const r = await axios.get(`https://api.exchangerate-api.com/v4/latest/${dari}`, { timeout: 10000 })
                        const rate = r.data.rates[ke]
                        if (!rate) throw new Error('Mata uang tidak ditemukan')
                        const result = (nilai * rate).toLocaleString('id-ID', { maximumFractionDigits: 4 })
                        await sendWithTyping(from, { text: `рҹ’ұ *KONVERSI MATA UANG*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ’ө *${nilai.toLocaleString()} ${dari}*\n= рҹ’° *${result} ${ke}*\nрҹ“Ҳ Rate: 1 ${dari} = ${rate.toLocaleString()} ${ke}\n\n_Data: ExchangeRate-API_` }, { quoted: msg })
                    } else {
                        // Unit conversion table
                        const units = {
                            'KM_MIL': 0.621371, 'MIL_KM': 1.60934,
                            'KG_LBS': 2.20462, 'LBS_KG': 0.453592,
                            'M_FT': 3.28084, 'FT_M': 0.3048,
                            'CM_IN': 0.393701, 'IN_CM': 2.54,
                            'L_GAL': 0.264172, 'GAL_L': 3.78541,
                            'KM_M': 1000, 'M_KM': 0.001,
                            'G_KG': 0.001, 'KG_G': 1000,
                        }
                        const key = `${dari}_${ke}`
                        if (units[key]) {
                            const result = (nilai * units[key]).toLocaleString('id-ID', { maximumFractionDigits: 6 })
                            await sendWithTyping(from, { text: `рҹ“җ *KONVERSI SATUAN*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ”ў *${nilai} ${dari}*\n= вң… *${result} ${ke}*` }, { quoted: msg })
                        } else if (dari === 'CELSIUS' && ke === 'FAHRENHEIT') {
                            const r = (nilai * 9/5 + 32).toFixed(2)
                            await sendWithTyping(from, { text: `рҹҢЎпёҸ *KONVERSI SUHU*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ”ў *${nilai}В°C* = вң… *${r}В°F*` }, { quoted: msg })
                        } else if (dari === 'FAHRENHEIT' && ke === 'CELSIUS') {
                            const r = ((nilai - 32) * 5/9).toFixed(2)
                            await sendWithTyping(from, { text: `рҹҢЎпёҸ *KONVERSI SUHU*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ”ў *${nilai}В°F* = вң… *${r}В°C*` }, { quoted: msg })
                        } else {
                            await sendWithTyping(from, { text: `вҡ пёҸ Konversi ${dari}вҶ’${ke} belum tersedia.\nYang tersedia: mata uang (USD/IDR/EUR dll), KM/MIL, KG/LBS, M/FT, CM/IN, L/GAL, CELSIUS/FAHRENHEIT` }, { quoted: msg })
                        }
                    }
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: `вқҢ Gagal konversi. Pastikan kode benar.\nContoh mata uang: USD IDR EUR` }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /cuacaminggu [kota] вҖ” Cuaca 7 hari dari API в•җв•җ
            if (lowerText.startsWith('.cuacaminggu ')) {
                const kota = fullText.slice(13).trim()
                if (!kota) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .cuacaminggu [kota]\nContoh: .cuacaminggu Jakarta' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const resp = await axios.get(`https://wttr.in/${encodeURIComponent(kota)}?format=j1`, { timeout: 12000, headers: { 'User-Agent': 'curl/7.68.0' } })
                    const w = resp.data
                    const area = w.nearest_area[0]
                    const areaName = area.areaName[0].value
                    const country = area.country[0].value
                    const weatherEmoji = (desc) => {
                        const d = desc.toLowerCase()
                        if (d.includes('sunny') || d.includes('clear')) return 'вҳҖпёҸ'
                        if (d.includes('rain') || d.includes('drizzle')) return 'рҹҢ§пёҸ'
                        if (d.includes('thunder') || d.includes('storm')) return 'вӣҲпёҸ'
                        if (d.includes('cloud') || d.includes('overcast')) return 'вҳҒпёҸ'
                        if (d.includes('fog') || d.includes('mist')) return 'рҹҢ«пёҸ'
                        if (d.includes('snow')) return 'вқ„пёҸ'
                        if (d.includes('partly')) return 'вӣ…'
                        return 'рҹҢӨпёҸ'
                    }
                    let txt = `рҹҢӨпёҸ *CUACA 7 HARI - ${areaName.toUpperCase()}, ${country}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                    w.weather.slice(0, 7).forEach(day => {
                        const desc = day.hourly[4]?.weatherDesc[0]?.value || '-'
                        const emoji = weatherEmoji(desc)
                        const rain = day.hourly[4]?.chanceofrain || 0
                        txt += `${emoji} *${day.date}*: ${day.mintempC}В°-${day.maxtempC}В°C | ${desc} | рҹҢ§пёҸ${rain}%\n`
                    })
                    txt += `\n_Data: wttr.in_`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: `вқҢ Kota "${kota}" tidak ditemukan.` }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /tanyaislam [pertanyaan] вҖ” Hadis/info Islam dari API в•җв•җ
            if (lowerText.startsWith('.tanyaislam ')) {
                const pertanyaan = fullText.slice(12).trim()
                if (!pertanyaan) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .tanyaislam [topik/kata kunci]\nContoh: .tanyaislam sabar\nContoh: .tanyaislam shalat' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    // Search hadith from Hadith API
                    let result = null
                    try {
                        const r = await axios.get(`https://api.hadith.gading.dev/books/bukhari?range=1-7563`, { timeout: 8000 })
                        const hadiths = r.data.data?.hadiths || []
                        // Simple keyword search
                        const keyword = pertanyaan.toLowerCase()
                        const found = hadiths.find(h => (h.arab + ' ' + (h.id || '')).toLowerCase().includes(keyword))
                        if (found) result = { arab: found.arab, id: found.id, number: found.number }
                    } catch(e) {}
                    if (!result) {
                        // Fallback: search via hadith API
                        const r2 = await axios.get(`https://api.hadith.gading.dev/books/muslim?range=1-3033`, { timeout: 8000 })
                        const hadiths2 = r2.data.data?.hadiths || []
                        const keyword = pertanyaan.toLowerCase()
                        const found2 = hadiths2.find(h => (h.arab + ' ' + (h.id || '')).toLowerCase().includes(keyword))
                        if (found2) result = { arab: found2.arab, id: found2.id, number: found2.number }
                    }
                    if (result) {
                        let txt = `вҳӘпёҸ *HADIS TERKAIT: ${pertanyaan.toUpperCase()}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                        txt += `рҹ“– *Hadis No. ${result.number}*\n\n`
                        if (result.arab) txt += `рҹ•Ң *Arab:*\n${result.arab.slice(0, 300)}\n\n`
                        if (result.id) txt += `рҹ“қ *Terjemahan:*\n${result.id.slice(0, 500)}\n\n`
                        txt += `_Sumber: Hadith API | Bukhari/Muslim_\n`
                        txt += `_вҡ пёҸ Untuk fatwa resmi, konsultasikan ke ulama._`
                        await sendWithTyping(from, { text: txt }, { quoted: msg })
                    } else {
                        // Fallback: Al-Quran API
                        const r3 = await axios.get(`https://api.quran.com/api/v4/search?q=${encodeURIComponent(pertanyaan)}&size=3&language=id`, { timeout: 8000, headers: { 'Accept': 'application/json' } })
                        const results3 = r3.data.search?.results || []
                        if (results3.length > 0) {
                            let txt = `рҹ“– *AYAT AL-QURAN: ${pertanyaan.toUpperCase()}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                            results3.slice(0, 3).forEach((v, i) => {
                                txt += `${i+1}. *${v.verse_key}*\n${v.text?.slice(0, 200) || ''}\n\n`
                            })
                            txt += `_Sumber: Quran.com API_`
                            await sendWithTyping(from, { text: txt }, { quoted: msg })
                        } else {
                            await sendWithTyping(from, { text: `вҡ пёҸ Tidak ditemukan hadis/ayat untuk "${pertanyaan}". Coba kata kunci lain.` }, { quoted: msg })
                        }
                    }
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal cari info Islam.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /jeniskucing [nama] вҖ” Info kucing dari API в•җв•җ
            if (lowerText.startsWith('.jeniskucing ')) {
                const ras = fullText.slice(13).trim()
                if (!ras) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .jeniskucing [nama ras]\nContoh: .jeniskucing persian\nContoh: .jeniskucing maine coon' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    // The Cat API
                    const r = await axios.get(`https://api.thecatapi.com/v1/breeds/search?q=${encodeURIComponent(ras)}`, { timeout: 10000, headers: { 'x-api-key': 'live_placeholder' } })
                    if (!r.data || r.data.length === 0) return await sendWithTyping(from, { text: `вқҢ Ras kucing "${ras}" tidak ditemukan. Coba nama dalam bahasa Inggris.\nContoh: persian, siamese, maine coon, british shorthair` }, { quoted: msg })
                    const cat = r.data[0]
                    let txt = `рҹҗұ *INFO KUCING: ${(cat.name || ras).toUpperCase()}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                    txt += `рҹ“ӣ *Nama:* ${cat.name || '-'}\n`
                    txt += `рҹҢҚ *Asal:* ${cat.origin || '-'}\n`
                    txt += `вҸі *Umur:* ${cat.life_span || '-'} tahun\n`
                    txt += `вҡ–пёҸ *Berat:* ${cat.weight?.metric || '-'} kg\n`
                    txt += `рҹ“қ *Deskripsi:* ${(cat.description || '-').slice(0, 250)}\n`
                    txt += `рҹ§  *Kecerdasan:* ${'вӯҗ'.repeat(cat.intelligence || 3)} (${cat.intelligence || 'N/A'}/5)\n`
                    txt += `вқӨпёҸ *Kasih sayang:* ${'вӯҗ'.repeat(cat.affection_level || 3)} (${cat.affection_level || 'N/A'}/5)\n`
                    txt += `рҹҸғ *Energi:* ${'вӯҗ'.repeat(cat.energy_level || 3)} (${cat.energy_level || 'N/A'}/5)\n`
                    txt += `рҹ§№ *Perawatan:* ${'вӯҗ'.repeat(cat.grooming || 3)} (${cat.grooming || 'N/A'}/5)\n`
                    if (cat.wikipedia_url) txt += `рҹ”— ${cat.wikipedia_url}\n`
                    txt += `\n_Data: TheCatAPI_`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal ambil info kucing.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /tebakkata вҖ” Game tebak kata в•җв•җ
            if (lowerText.startsWith('.tebakkata')) {
                if (!fs.existsSync('./tebakkata.json')) fs.writeFileSync('./tebakkata.json', '{}')
                let tkData = JSON.parse(fs.readFileSync('./tebakkata.json', 'utf8'))
                const args = fullText.split(' ').slice(1).join(' ').trim()
                if (!args) {
                    await reactWait(from, msg.key)
                    try {
                        const pool = [
                            {word:'kucing', hint:'Hewan peliharaan yang suka tidur dan mandi sendiri'},
                            {word:'harimau', hint:'Raja hutan berkaki empat dengan belang hitam'},
                            {word:'pesawat', hint:'Kendaraan yang terbang di langit membawa penumpang'},
                            {word:'komputer', hint:'Alat elektronik untuk bekerja dan browsing internet'},
                            {word:'jendela', hint:'Lubang di dinding rumah yang bisa dibuka tutup'},
                            {word:'matahari', hint:'Bintang terdekat bumi yang memberi cahaya di siang hari'},
                            {word:'telepon', hint:'Alat komunikasi yang bisa dipakai untuk menelepon'},
                            {word:'mobil', hint:'Kendaraan beroda empat bertenaga mesin'},
                            {word:'bunga', hint:'Bagian tumbuhan yang berwarna-warni dan harum'},
                            {word:'bintang', hint:'Objek langit yang bersinar di malam hari'},
                        ]
                        const soal = pool[Math.floor(Math.random() * pool.length)]
                        tkData[from + '_' + senderNumber] = { word: soal.word, time: Date.now() }
                        fs.writeFileSync('./tebakkata.json', JSON.stringify(tkData, null, 2))
                        await sendWithTyping(from, { text: `рҹ“– *TEBAK KATA!*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ’¬ *Petunjuk:*\n"${soal.hint}"\n\nрҹ”Ө Jumlah huruf: *${soal.word.length} huruf*\nJawab: /tebakkata [jawaban]\nвҸұпёҸ Timeout: 60 detik` }, { quoted: msg })
                        await reactDone(from, msg.key)
                    } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal buat soal.' }, { quoted: msg }); await reactDone(from, msg.key) }
                    return
                }
                const key = from + '_' + senderNumber
                const game = tkData[key]
                if (!game) return await sendWithTyping(from, { text: 'вҡ пёҸ Belum ada game! Ketik /tebakkata untuk mulai.' }, { quoted: msg })
                if (Date.now() - game.time > 60000) {
                    delete tkData[key]; fs.writeFileSync('./tebakkata.json', JSON.stringify(tkData, null, 2))
                    return await sendWithTyping(from, { text: `вҸұпёҸ *Waktu habis!*\nJawabannya: *${game.word}*` }, { quoted: msg })
                }
                if (args.toLowerCase().trim() === game.word.toLowerCase()) {
                    delete tkData[key]; fs.writeFileSync('./tebakkata.json', JSON.stringify(tkData, null, 2))
                    return await sendWithTyping(from, { text: `рҹҺү *BENAR! @${senderNumber}*\nвң… Kata: *${game.word}*\nрҹҸҶ Keren banget!`, mentions: [senderJid] }, { quoted: msg })
                }
                return await sendWithTyping(from, { text: `вқҢ *Salah!* Coba lagi.\nрҹ”Ө Jumlah huruf: *${game.word.length} huruf*\nJawab: /tebakkata [jawaban]` }, { quoted: msg })
            }

            // в•җв•җ /hobimu [kepribadian] вҖ” Rekomendasi hobi в•җв•җ
            if (lowerText.startsWith('.hobimu ')) {
                const kepribadian = fullText.slice(8).trim()
                if (!kepribadian) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .hobimu [tipe kepribadian]\nContoh: .hobimu introvert\nContoh: .hobimu suka outdoor\nContoh: .hobimu kreatif' }, { quoted: msg })
                await reactWait(from, msg.key)
                // Rekomendasi berdasarkan keyword
                const hobis = {
                    introvert: ['Membaca buku рҹ“ҡ','Coding/Programming рҹ’»','Melukis/Menggambar рҹҺЁ','Menulis cerita вңҚпёҸ','Fotografi рҹ“ё'],
                    ekstrovert: ['Vlogging/YouTube рҹҺ¬','Olahraga tim вҡҪ','Stand-up comedy рҹҺӨ','Traveling рҹҢҚ','Komunitas sosial рҹӨқ'],
                    kreatif: ['Digital art рҹҺЁ','Music production рҹҺө','DIY kerajinan вңӮпёҸ','Video editing рҹҺ¬','Desain grafis рҹ’Ў'],
                    outdoor: ['Hiking/Mendaki рҹҸ”пёҸ','Bersepeda рҹҡҙ','Berkebun рҹҢұ','Berenang рҹҸҠ','Fotografi alam рҹ“ё'],
                    teknologi: ['Programming рҹ’»','Robotik рҹӨ–','Game development рҹҺ®','3D printing рҹ–ЁпёҸ','Arduino/IoT вҡЎ'],
                }
                const key = Object.keys(hobis).find(k => kepribadian.toLowerCase().includes(k))
                const list = key ? hobis[key] : ['Membaca рҹ“ҡ','Memasak рҹҚі','Olahraga рҹҸғ','Musik рҹҺө','Fotografi рҹ“ё']
                let txt = `рҹҺҜ *REKOMENDASI HOBI*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ‘Ө Tipe: *${kepribadian}*\n\n`
                list.forEach((h, i) => txt += `${i+1}. ${h}\n`)
                txt += `\nрҹ’Ў *Tips:* Mulai dari yang paling menarik minatmu!`
                await sendWithTyping(from, { text: txt }, { quoted: msg })
                await reactDone(from, msg.key); return
            }

            // в•җв•җ /singkat вҖ” Ringkas teks (reply atau langsung) в•җв•җ
            if (lowerText.startsWith('.singkat') && (fullText.length > 9 || msg.message.extendedTextMessage?.contextInfo?.quotedMessage)) {
                let teksInput = fullText.slice(8).trim()
                const qmSg = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                if (!teksInput && qmSg) teksInput = qmSg.conversation || qmSg.extendedTextMessage?.text || ''
                if (!teksInput) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .singkat [teks]\nAtau: reply pesan + /singkat' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    // Split sentences and take key points
                    const sentences = teksInput.replace(/([.!?])\s+/g, '$1\n').split('\n').map(s => s.trim()).filter(s => s.length > 20)
                    const maxSentences = Math.min(4, Math.ceil(sentences.length * 0.3) || 2)
                    const summary = sentences.slice(0, maxSentences).join(' ')
                    const ratio = Math.round((1 - summary.length / teksInput.length) * 100)
                    await sendWithTyping(from, { text: `рҹ“қ *RINGKASAN*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n${summary}\n\nрҹ“Ҡ Dipangkas ${ratio > 0 ? ratio : 0}% dari teks asli (${teksInput.length} вҶ’ ${summary.length} karakter)` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal meringkas.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /perbaiki [teks] вҖ” Perbaiki ejaan sederhana в•җв•җ
            if (lowerText.startsWith('.perbaiki') && (fullText.length > 10 || msg.message.extendedTextMessage?.contextInfo?.quotedMessage)) {
                let teksInput2 = fullText.slice(10).trim()
                const qmPb = msg.message.extendedTextMessage?.contextInfo?.quotedMessage
                if (!teksInput2 && qmPb) teksInput2 = qmPb.conversation || qmPb.extendedTextMessage?.text || ''
                if (!teksInput2) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .perbaiki [teks]\nAtau: reply pesan + /perbaiki' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    // Basic Indonesian spell corrections
                    const corrections = {
                        'gw': 'saya', 'lo': 'kamu', 'lu': 'kamu', 'yg': 'yang', 'dgn': 'dengan',
                        'trs': 'terus', 'bgt': 'banget', 'utk': 'untuk', 'krn': 'karena',
                        'ga': 'tidak', 'gak': 'tidak', 'ngga': 'tidak', 'nggak': 'tidak',
                        'udah': 'sudah', 'udh': 'sudah', 'blm': 'belum', 'sdh': 'sudah',
                        'skrg': 'sekarang', 'bkn': 'bukan', 'emg': 'memang', 'emang': 'memang',
                        'klo': 'kalau', 'kalo': 'kalau', 'gmn': 'bagaimana', 'gmana': 'bagaimana',
                        'aja': 'saja', 'deh': '', 'sih': '', 'lah': '', 'dong': '',
                        'sm': 'sama', 'biar': 'agar', 'nyg': 'yang', 'dr': 'dari', 'ke': 'ke',
                    }
                    let result = teksInput2
                    let fixes = []
                    Object.entries(corrections).forEach(([salah, benar]) => {
                        const regex = new RegExp('\\b' + salah + '\\b', 'gi')
                        if (regex.test(result) && benar) {
                            fixes.push(`"${salah}" вҶ’ "${benar}"`)
                            result = result.replace(regex, benar)
                        }
                    })
                    // Capitalize first letter
                    result = result.charAt(0).toUpperCase() + result.slice(1)
                    // Add period if missing
                    if (result && !'.!?'.includes(result.slice(-1))) result += '.'
                    let txt = `вңҸпёҸ *PERBAIKAN TEKS*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                    txt += `рҹ“қ *Asli:*\n${teksInput2.slice(0, 300)}\n\n`
                    txt += `вң… *Diperbaiki:*\n${result.slice(0, 300)}\n\n`
                    if (fixes.length > 0) txt += `рҹ”§ *Koreksi:* ${fixes.slice(0, 8).join(', ')}`
                    else txt += `вң… Tidak ditemukan kesalahan umum.`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal perbaiki teks.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /buatpuisi [tema] вҖ” Generate puisi dari API в•җв•җ
            if (lowerText.startsWith('.buatpuisi ')) {
                const tema = fullText.slice(11).trim()
                if (!tema) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .buatpuisi [tema]\nContoh: .buatpuisi rindu\nContoh: .buatpuisi persahabatan' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const result = await askAI(`Buat puisi indah 3 bait bertema "${tema}" dalam bahasa Indonesia. Setiap bait 4 baris, ada rima di akhir baris. Format: langsung puisinya saja tanpa penjelasan.`, senderNumber)
                    await sendWithTyping(from, { text: `рҹҢё *PUISI: ${tema.toUpperCase()}*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n${result}\n\n_вҖ” Roma Bot Poet_ рҹ–ҠпёҸ` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal buat puisi.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /buatcerita [tema] вҖ” Generate cerita dari API в•җв•җ
            if (lowerText.startsWith('.buatcerita ')) {
                const temaCerita = fullText.slice(12).trim()
                if (!temaCerita) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .buatcerita [tema]\nContoh: .buatcerita petualangan di hutan' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const result = await askAI(`Buat cerita pendek menarik bertema "${temaCerita}" dalam bahasa Indonesia. Ada tokoh, konflik, dan penyelesaian. Panjang 150-200 kata. Langsung ceritanya saja.`, senderNumber)
                    await sendWithTyping(from, { text: `рҹ“– *CERITA PENDEK*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ“Ң Tema: ${temaCerita}\n\n${result}\n\n_вҖ” Roma Bot Stories_ рҹ“ҡ` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal buat cerita.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

            // в•җв•җ /lawak вҖ” Jokes dari Official Joke API в•җв•җ
            if (lowerText === '.lawak') {
                await reactWait(from, msg.key)
                try {
                    let setup = '', punchline = ''
                    try {
                        const r = await axios.get('https://official-joke-api.appspot.com/random_joke', { timeout: 8000 })
                        setup = r.data.setup; punchline = r.data.punchline
                        // Translate to Indonesian
                        const tr1 = await axios.get(`https://translate.googleapis.com/translate_a/single?client=gtx&sl=en&tl=id&dt=t&q=${encodeURIComponent(setup)}`, { timeout: 8000, headers: {'User-Agent':'Mozilla/5.0'} })
                        const tr2 = await axios.get(`https://translate.googleapis.com/translate_a/single?client=gtx&sl=en&tl=id&dt=t&q=${encodeURIComponent(punchline)}`, { timeout: 8000, headers: {'User-Agent':'Mozilla/5.0'} })
                        setup = tr1.data[0].map(x=>x[0]).filter(Boolean).join('')
                        punchline = tr2.data[0].map(x=>x[0]).filter(Boolean).join('')
                    } catch(e) {
                        const localJokes = [
                            { s: 'Kenapa matematika itu menyedihkan?', p: 'Karena banyak masalah!' },
                            { s: 'Apa yang bisa terbang tapi tidak bersayap?', p: 'Waktu!' },
                            { s: 'Kenapa ikan tidak bisa bermain gitar?', p: 'Karena tidak punya jari!' },
                            { s: 'Apa yang selalu jatuh tapi tidak pernah terluka?', p: 'Hujan!' },
                            { s: 'Kenapa lift tidak bisa bercanda?', p: 'Karena levelnya beda!' },
                        ]
                        const j = localJokes[Math.floor(Math.random() * localJokes.length)]
                        setup = j.s; punchline = j.p
                    }
                    await sendWithTyping(from, { text: `рҹҳӮ *JOKES OF THE DAY*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\nвқ“ ${setup}\n\nрҹ’¬ ${punchline}\n\nрҹҳӮ _Jangan ketawa sendirian!_` }, { quoted: msg })
                    await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: 'вқҢ Gagal ambil jokes.' }, { quoted: msg }); await reactDone(from, msg.key) }
                return
            }

