                    await sendWithTyping(from, { audio: Buffer.from(audioResp.data), mimetype: 'audio/mpeg', ptt: true }, { quoted: msg })
                    await sendWithTyping(from, { text: `рҹҢҗ *TERJEMAH SUARA*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ“қ Asli (${detectedLang}): ${teksTS.slice(0,100)}\nвң… Terjemahan (${lang}): ${translated.slice(0,100)}` }, { quoted: msg })
