                const tinggi = parseFloat(parts[0]), berat = parseFloat(parts[1])
                if (isNaN(tinggi) || isNaN(berat) || tinggi <= 0 || berat <= 0) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .bmi [tinggi cm] [berat kg]\nContoh: .bmi 170 65' }, { quoted: msg })
                const bmi = (berat / Math.pow(tinggi / 100, 2)).toFixed(1)
                let kategori = '', saran = ''
                if (bmi < 18.5) { kategori = 'Kurus (Underweight)'; saran = 'Tambah asupan kalori dan protein, konsultasi dokter gizi.' }
                else if (bmi < 25) { kategori = 'Normal (Ideal)'; saran = 'Pertahankan pola makan sehat dan olahraga rutin!' }
                else if (bmi < 30) { kategori = 'Gemuk (Overweight)'; saran = 'Kurangi kalori, perbanyak sayur & buah, olahraga minimal 30 menit/hari.' }
                else { kategori = 'Obesitas'; saran = 'Konsultasikan dengan dokter atau ahli gizi segera.' }
                let txt = `вҡ–пёҸ *KALKULATOR BMI*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n`
                txt += `Tinggi: ${tinggi} cm\nBerat: ${berat} kg\n`
