                if (!tipe || isNaN(nilai)) return await sendWithTyping(from, { text: 'вҡ пёҸ Format: .suhukonversi [c/f] [nilai]\nContoh: .suhukonversi c 100\nContoh: .suhukonversi f 212' }, { quoted: msg })
                if (tipe === 'c') {
                    const f = (nilai * 9/5 + 32).toFixed(2)
                    const k = (nilai + 273.15).toFixed(2)
                    await sendWithTyping(from, { text: `рҹҢЎпёҸ *KONVERSI SUHU*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n${nilai}В°C = ${f}В°F = ${k}K` }, { quoted: msg })
                } else if (tipe === 'f') {
                    const c = ((nilai - 32) * 5/9).toFixed(2)
                    const k = ((nilai - 32) * 5/9 + 273.15).toFixed(2)
                    await sendWithTyping(from, { text: `рҹҢЎпёҸ *KONVERSI SUHU*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n${nilai}В°F = ${c}В°C = ${k}K` }, { quoted: msg })
                } else {
                    await sendWithTyping(from, { text: 'вҡ пёҸ Tipe harus "c" (Celsius) atau "f" (Fahrenheit)' }, { quoted: msg })
                }
