                const parts = tglLahir.split('-')
                if (parts.length !== 3) return await sendWithTyping(from, { text: 'вҡ пёҸ Format tanggal salah! Contoh: 17-08-2000' }, { quoted: msg })
                const lahir = new Date(parseInt(parts[2]), parseInt(parts[1])-1, parseInt(parts[0]))
                if (isNaN(lahir.getTime())) return await sendWithTyping(from, { text: 'вҡ пёҸ Tanggal tidak valid!' }, { quoted: msg })
                const now = new Date()
                let umur = now.getFullYear() - lahir.getFullYear()
                if (now.getMonth() < lahir.getMonth() || (now.getMonth() === lahir.getMonth() && now.getDate() < lahir.getDate())) umur--
                const nextBday = new Date(now.getFullYear(), lahir.getMonth(), lahir.getDate())
                if (nextBday < now) nextBday.setFullYear(now.getFullYear() + 1)
                const daysLeft = Math.ceil((nextBday - now) / (1000 * 60 * 60 * 24))
                await sendWithTyping(from, { text: `рҹҺӮ *HITUNG UMUR*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nTanggal lahir: ${tglLahir}\nUmur sekarang: *${umur} tahun*\nHari lahir: ${lahir.toLocaleDateString('id-ID',{weekday:'long'})}\nUltah berikutnya: ${daysLeft} hari lagi` }, { quoted: msg }); return
