                    popular.forEach(c => { if (rates[c]) txt += `${c}: ${rates[c].toLocaleString('id-ID')}\n` })
                    txt += `\nUpdate: ${new Date(r.data.date).toLocaleDateString('id-ID')}\n_Sumber: ExchangeRate-API_`
                    await sendWithTyping(from, { text: txt }, { quoted: msg })
