                    if (!c) return await sendWithTyping(from, { text: `вқҢ Negara tidak ditemukan.` }, { quoted: msg })
                    const name = c.name?.common || namaInput
                    // Scrape HDI from Wikipedia
                    const wikiR = await axios.get(`https://en.wikipedia.org/w/api.php?action=query&titles=${encodeURIComponent(name)}&prop=extracts&exintro=true&explaintext=true&format=json&exsentences=10`, { timeout: 10000 })
                    const pages = wikiR.data.query?.pages || {}
                    const pageText = Object.values(pages)[0]?.extract || ''
                    // Extract HDI info from text
                    const hdiMatch = pageText.match(/HDI[^0-9]*([0-9.]+)/i) || pageText.match(/Human Development Index[^0-9]*([0-9.]+)/i)
                    const hdiVal = hdiMatch ? hdiMatch[1] : 'Data tidak tersedia'
