                    const _imgBuf = await axios.get(_imgUrl, { responseType: 'arraybuffer', timeout: 20000, headers: { 'User-Agent': _imgUA, 'Referer': 'https://duckduckgo.com/' }, maxRedirects: 5 })
                    const _imgContentType = _imgBuf.headers['content-type'] || 'image/jpeg'
                    if (!_imgContentType.includes('image')) throw new Error('Bukan file gambar')
